 52→function AuthNavigator() {
 53→  const {colors} = useTheme();
 54→  return (
 55→    <AuthStackNav.Navigator
 56→      screenOptions={{
 57→        headerStyle: {backgroundColor: colors.bgElevated},
 58→        headerTintColor: colors.textPrimary,
 59→        headerShadowVisible: false,
 60→      }}>
 61→      <AuthStackNav.Screen
 62→        name="Login"
 63→        component={LoginScreen}
 64→        options={{headerShown: false}}
 65→      />
 66→      <AuthStackNav.Screen
 67→        name="SignUp"
 68→        component={SignUpScreen}
 69→        options={{headerShown: false}}
 70→      />
 71→      <AuthStackNav.Screen
 72→        name="ForgotPassword"
 73→        component={ForgotPasswordScreen}
 74→        options={{headerShown: false}}
 75→      />
 76→    </AuthStackNav.Navigator>
 77→  );
 78→}
